mapper.select:
select v.*,
       case when exists (
           select 1
           from tbl_post_like pl
           where pl.post_id = v.id
             and pl.member_id = #{memberId}
       ) then true else false end as is_liked,
       case when exists (
           select 1
           from tbl_bookmark b
           where b.post_id = v.id
             and b.member_id = #{memberId}
       ) then true else false end as is_bookmarked
from view_post_feed v
where v.member_id = #{memberId}
  and not exists (
    select 1
    from tbl_post_product pp
    where pp.id = v.id
)
order by v.created_datetime desc
limit #{criteria.count}
    offset #{criteria.offset}

select v.*,
       true as is_liked,
       case when exists (
           select 1
           from tbl_bookmark b
           where b.post_id = v.id
             and b.member_id = #{memberId}
       ) then true else false end as is_bookmarked
from view_post_feed v
         join tbl_post_like pl on pl.post_id = v.id
where pl.member_id = #{memberId}
  and not exists (
    select 1
    from tbl_post_product pp
    where pp.id = v.id
)
order by pl.created_datetime desc
limit #{criteria.count}
offset #{criteria.offset}

select ,
       p.post_read_count
from tbl_post p
join tbl_member m on p.member_id = m.id
where p.member_id = #{memberId}
  and p.post_status = 'active'
  and p.reply_post_id is not null
order by p.created_datetime desc
limit #{criteria.count}
offset #{criteria.offset}

select from tbl_post p join tbl_member m on p.member_id = m.id where p.reply_post_id in
#{id}
and p.post_status = 'active' and p.member_id not in (select bl.blocked_id from tbl_block bl where bl.blocker_id = #{memberId}) and p.member_id not in (select bl.blocker_id from tbl_block bl where bl.blocked_id = #{memberId}) order by p.created_datetime asc
